// --- 3D CARD COMPONENT ---
function FloatingCard({ member, index, total, onHover }: any) {
  const mesh = useRef<THREE.Group>(null!)
  const [hovered, setHover] = useState(false)
  
  // Calculate orbital position
  const angle = (index / total) * Math.PI * 2
  const radius = 7

  useFrame((state) => {
    const t = state.clock.getElapsedTime()
    // Periodic floating motion
    mesh.current.position.y = Math.sin(t + index) * 0.2
    
    // Smoothly tilt toward mouse when hovered
    if (hovered) {
      mesh.current.rotation.y = THREE.MathUtils.lerp(mesh.current.rotation.y, state.mouse.x * 0.5, 0.1)
      mesh.current.rotation.x = THREE.MathUtils.lerp(mesh.current.rotation.x, -state.mouse.y * 0.5, 0.1)
    } else {
      mesh.current.rotation.y = THREE.MathUtils.lerp(mesh.current.rotation.y, 0, 0.05)
      mesh.current.rotation.x = THREE.MathUtils.lerp(mesh.current.rotation.x, 0, 0.05)
    }
  })

  return (
    <group 
      ref={mesh} 
      position={[Math.cos(angle) * radius, 0, Math.sin(angle) * radius]}
    >
      <Float speed={1.5} rotationIntensity={0.1} floatIntensity={0.4}>
        <mesh 
          onPointerOver={() => { setHover(true); onHover(member); }} 
          onPointerOut={() => { setHover(false); onHover(null); }}
        >
          <planeGeometry args={[3, 4]} />
          <Suspense fallback={<meshStandardMaterial color="#334155" />}>
            <Image url={member.image} transparent opacity={1} side={THREE.DoubleSide} />
          </Suspense>
        </mesh>

        {/* Backglow Aura */}
        <mesh position={[0, 0, -0.1]}>
          <planeGeometry args={[3.3, 4.3]} />
          <MeshDistortMaterial 
            color={hovered ? member.color : "#1e293b"} 
            speed={3} 
            distort={0.4} 
            radius={1} 
          />
        </mesh>

        {/* Name Plate in 3D */}
        <Text
          position={[0, -2.6, 0.1]}
          fontSize={0.2}
          color="white"
          font="https://fonts.gstatic.com/s/inter/v12/UcCO3FwrK3iLTeHuS_fvQtMwCp50KnMw2boKoduKmMEVuLyfMZhrib2Bg-4.ttf"
        >
          {member.name.toUpperCase()}
        </Text>
      </Float>
    </group>
  )
}

